                extTypeInfo.getSQL(builder, sqlFlags).append(' ');
            }
            builder.append("ARRAY");
            if (precision >= 0L) {
                builder.append('[').append(precision).append(']');
            }
            break;
        case Value.ROW:
            builder.append("ROW");
            if (extTypeInfo != null) {
                extTypeInfo.getSQL(builder, sqlFlags);
            }
            break;
        default:
            builder.append(Value.getTypeName(valueType));
        }
        return builder;
    }

